# nginx.conf  –  dark launch mirroring
http {
  upstream prod_agent {
    server agent-prod.internal:8080;
  }

  upstream shadow_agent {
    server agent-shadow.internal:8080;
  }

  server {
    listen 443 ssl;
    server_name api.example.com;

    # Mirror body must be buffered for the sub-request
    mirror_request_body on;

    location /v1/agent/chat {
      mirror /shadow;            # fire shadow sub-request
      mirror_request_body on;

      proxy_pass http://prod_agent;
      proxy_set_header Host $host;
      proxy_set_header X-Request-Id $request_id;
    }

    # Internal shadow location — not directly accessible
    location = /shadow {
      internal;
      proxy_pass http://shadow_agent/v1/agent/chat;
      proxy_set_header X-Dark-Launch "true";
      proxy_set_header X-Shadow-Trace-Id $request_id;
      proxy_set_header X-Forwarded-For $remote_addr;
      # Shadow failures are silently dropped
    }
  }
}
